// Generated from Sprint 59 — Task 59-1 (Linux Flatpak パッケージ作成)
// CoDD trace: plan:implementation_plan > governance:adr_tech_stack
// Module: ui_foundation | Platform: linux
// Convention: framework:tauri — Tauri (Rust + WebView) requires offline Cargo sources in Flatpak

import type { FlatpakSource } from './types';

/**
 * In Flatpak builds, network access is disabled during the build phase.
 * Cargo dependencies must be pre-downloaded and provided as sources.
 *
 * This module generates the cargo sources configuration for the Flatpak manifest.
 * The actual cargo sources are generated by `flatpak-cargo-generator.py`
 * (from the flatpak-builder-tools repository) and stored as a JSON file.
 *
 * Usage:
 *   python3 flatpak-cargo-generator.py src-tauri/Cargo.lock -o cargo-sources.json
 */

/**
 * Generate the inline Cargo config that redirects crates.io to vendored sources.
 * This is injected into the Flatpak build environment.
 */
export function generateCargoConfigInline(): FlatpakSource {
  const cargoConfig = `[source.crates-io]
replace-with = "vendored-sources"

[source.vendored-sources]
directory = "cargo/vendor"
`;

  return {
    type: 'inline',
    contents: cargoConfig,
    destFilename: '.cargo/config.toml',
  };
}

/**
 * Generate a file source reference for the pre-generated cargo sources JSON.
 * The cargo sources JSON is produced by flatpak-cargo-generator.py.
 */
export function generateCargoSourcesFileRef(cargoSourcesPath: string): FlatpakSource {
  return {
    type: 'file',
    path: cargoSourcesPath,
    destFilename: 'cargo-sources.json',
  };
}

/**
 * Generate the command to produce the cargo sources JSON from Cargo.lock.
 * This command should be run before building the Flatpak.
 */
export function generateCargoSourcesCommand(projectRoot: string): string {
  return [
    'python3',
    'flatpak-cargo-generator.py',
    `${projectRoot}/src-tauri/Cargo.lock`,
    '-o',
    `${projectRoot}/flatpak/cargo-sources.json`,
  ].join(' ');
}

/**
 * Generate the command to download the flatpak-cargo-generator tool.
 */
export function generateToolDownloadCommand(): string {
  return [
    'curl -L -o flatpak-cargo-generator.py',
    'https://raw.githubusercontent.com/nickel-org/nickel.rs/master/nickel/flatpak-cargo-generator.py',
    '||',
    'wget -O flatpak-cargo-generator.py',
    'https://github.com/nickel-org/nickel.rs/raw/master/nickel/flatpak-cargo-generator.py',
  ].join(' \\\n  ');
}

/**
 * Generate npm/node sources configuration for offline Flatpak build.
 * Node modules must also be provided as offline sources.
 */
export function generateNodeSourcesCommand(projectRoot: string): string {
  return [
    'flatpak-node-generator',
    'npm',
    `${projectRoot}/package-lock.json`,
    '-o',
    `${projectRoot}/flatpak/node-sources.json`,
  ].join(' ');
}

/**
 * Core Rust crate dependencies required by Tauri for the PromptNotes build.
 * These are the direct dependencies declared in src-tauri/Cargo.toml.
 * The full transitive dependency tree is resolved by flatpak-cargo-generator.
 */
export const CORE_TAURI_DEPENDENCIES = [
  'tauri',
  'serde',
  'serde_json',
  'serde_yaml',
  'chrono',
  'dirs',
  'regex',
] as const;
